Delta_TC = 1E7                              #Delta_t/C
Vth = 2.45                                  #Threshold voltage
LR = 8.4                                    #Learning rate
Step= 5                                     #Upper and lower limits of weight change
Ratio = 2.05                                #The ratio of specified rows to non-specified rows
Shift_value = 21.3                          #Time offset

